import React from 'react';

const SubmissionTable = ({ submissions, onSubmissionClick }) => {

  const getStatusClass = (status) => {
    if (status === 'Approved') return 'status-approved';
    if (status?.includes('Review')) return 'status-pending';
    if (status === 'Critical') return 'status-critical';
    return 'status-warning';
  };

  const getRiskClass = (riskLevel) => {
    if (riskLevel === 'Critical') return 'status-critical';
    if (riskLevel === 'High') return 'status-warning';
    return 'status-approved';
  };

  const formatCurrency = (value) => {
    return `$${value.toFixed(1)}B`;
  };

  const getProgressWidth = (days) => {
    // Normalize to 0-100% based on typical review time (500 days max)
    return Math.min((days / 500) * 100, 100);
  };

  const getProgressColor = (days, variance) => {
    if (variance > 60) return '#EF4444'; // Red - critical
    if (variance > 30) return '#F59E0B'; // Amber - warning
    if (days > 300) return '#F59E0B'; // Amber - long review
    return '#22C55E'; // Green - on track
  };

  return (
    <div className="submission-table-container">
      <table className="submission-table">
        <thead>
          <tr>
            <th>Protocol / Product</th>
            <th>Country</th>
            <th>Status</th>
            <th>Days in Review</th>
            <th>Peak Revenue</th>
            <th>Risk</th>
          </tr>
        </thead>
        <tbody>
          {submissions.map((sub) => (
            <tr 
              key={sub.Protocol_ID} 
              onClick={() => onSubmissionClick(sub.Protocol_ID)}

              className="clickable-row"
              title="Click for details"
            >
              <td>
                <div className="protocol-id">{sub.Protocol_ID}</div>
                <div className="product-name">{sub.Product}</div>
              </td>
              <td>
                <div className="country-name">
                  {sub.Country}
                </div>
              </td>
              <td>
                <span className={`status-pill ${getStatusClass(sub.Submission_Status)}`}>
                  {sub.Submission_Status}
                </span>
              </td>
              <td>
                <div className="days-bar-wrap">
                  <div className="days-bar-bg">
                    <div 
                      className="days-bar-fill" 
                      style={{
                        width: `${getProgressWidth(sub.Clock_Stop_Days || 0)}%`,
                        background: getProgressColor(sub.Clock_Stop_Days || 0, 0)
                      }}
                    ></div>
                  </div>
                  <div className="days-num">{sub.Clock_Stop_Days || 0}d</div>
                </div>
              </td>
              <td>
                <div className="revenue-val">
                  {sub.Peak_Sales_Millions != null ? `${(sub.Peak_Sales_Millions).toFixed(0)}M` : '—'}
                </div>
              </td>
              <td>
                <span className={`status-pill ${getRiskClass(sub.Submission_Status)}`}>
                  {sub.Submission_Status || '—'}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {submissions.length === 0 && (
        <div className="empty-state">
          <p>No submissions match the current filters</p>
        </div>
      )}
    </div>
  );
};

export default SubmissionTable;
